def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 15):
                val = np.exp(-ratio * a * 1.1) * (a ** 3.1)
                if a % 4 == 0:
                    val *= 0.85
                elif a % 2 == 0:
                    val *= 1.12
                else:
                    val *= 1.07
                score += val
            if (int(capacity) * int(item)) % 7 == 0:
                score *= 0.79
            if score > 12:
                score /= 3.1
        elif 0.05 <= ratio < 0.25:
            prod = 1
            for n in range(1, max(3, int(capacity // 2)) + 3):
                prod *= (ratio + n / (n + 2))
                if prod > 5e6:
                    prod = np.log1p(prod) ** 1.4
                    break
            mod_val = int(prod) % 420
            score += np.sqrt(ratio * mod_val + 2)
            if (int(capacity) % 5 == 0 and int(item * 10) % 4 == 0):
                score += 6.7
            else:
                score -= 1.1
            extra_sum = 0
            for x in range(1, 8):
                extra_sum += ((ratio * x**3) % 1) * (x ** 2.8)
            score += extra_sum / 6
        elif 0.25 <= ratio <= 0.55:
            for m in range(1, 9):
                inc = (ratio ** (m + 3)) * (m ** 3.1) / ((m + 3) ** 1.1)
                score += inc
            remainder = capacity - item
            if remainder < 4:
                score += 12 + remainder * 0.6
            else:
                score -= remainder * 1.1
            if score < -7:
                score = abs(score) * 0.35 + 3
            if int(capacity) % 9 == 0:
                score *= 1.3
            if score > 18:
                score /= 3.7
        elif 0.55 < ratio <= 0.85:
            penalty_base = 0
            for p in range(1, 13):
                term = ((ratio - 0.55) ** p) * (p ** 1.9)
                penalty_base += term
                if penalty_base > 65:
                    penalty_base = np.log1p(penalty_base) ** 1.3
                    break
            score = penalty_base * 14
            if capacity < item * 1.07:
                score += 18
            if (int(capacity * 6) % 8 == 0) and (int(item * 9) % 13 == 0):
                score -= 7
            if score < 0:
                score *= -1.7
                score += 7
            if score > 130:
                score = 130
        elif 0.85 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.85
            for q in range(1, 13):
                penalty_ext += ((diff) ** q) * (q ** 3.1) / (q + 2)
            score = penalty_ext * 25
            if capacity < item * 1.5:
                score += 25
            if (int(capacity * 4) % 6 == 0) and (int(item * 10) % 5 == 0):
                score -= 9
            for z in range(1, 8):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.65
            if score > 1400:
                score = 1400
        elif 1.2 < ratio <= 1.7:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.7)
                if term > 15000:
                    term = np.sqrt(term) * 1.2
                super_penalty += term
            score = super_penalty * 30
            if capacity < item * 2.2:
                score += 35
            if (int(capacity * 15) % 6 == 0) and (int(item * 20) % 7 == 0):
                score -= 12
            for w in range(2, 9):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.7 + 5
            if score > 2500:
                score = 2500
        else:
            mega_penalty = 0
            diff = ratio - 1.7
            for s in range(1, 18):
                term = ((diff) ** s) * (s ** 4)
                if term > 20000:
                    term = np.log1p(term) * 2
                mega_penalty += term
            score = mega_penalty * 40
            if capacity < item * 3:
                score += 40
            if (int(capacity * 20) % 5 == 0) and (int(item * 25) % 6 == 0):
                score -= 15
            for u in range(3, 10):
                score += ((diff / u) % 1) * (u * 3)
            if score < 0:
                score = abs(score) * 0.8 + 7
            if score > 3000:
                score = 3000
        if capacity > 250:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 7:
            score *= 2.8
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        high_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        mean_val = np.mean(finite_priorities)
        fill_value = np.max(finite_priorities) * (10 + high_count) - median_val + (mean_val * 0.7)
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
